 1	import React, { FC } from 'react';
 2	
 3	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Button, Stack, StackItem, Text, TextVariants } from '@patternfly/react-core';
 6	import { ExternalLinkSquareAltIcon } from '@patternfly/react-icons';
 7	
 8	const SysprepInfo: FC = () => {
 9	  const { t } = useKubevirtTranslation();
10	
11	  return (
12	    <div data-test="sysprep-info">
13	      <Stack>
14	        <StackItem>
15	          <Text className="kv-sysprep-info" component={TextVariants.p}>
16	            {t(
17	              'Sysprep is an automation tool for Windows that automates Windows setup, and custom software provisioning.',
18	            )}
19	          </Text>
20	        </StackItem>
21	        <StackItem className="text-muted">
22	          {t(
23	            'An answer file is an XML-based file that contains setting definitions and values to use during Windows Setup',
24	          )}{' '}
25	          <Button
26	            icon={<ExternalLinkSquareAltIcon />}
27	            iconPosition="right"
28	            isInline
29	            size="sm"
30	            variant="link"
31	          >
32	            <a href={documentationURL.SYSPREP} rel="noopener noreferrer" target="_blank">
33	              {t('Learn more')}
34	            </a>
35	          </Button>
36	        </StackItem>
37	      </Stack>
38	    </div>
39	  );
40	};
41	
42	export default SysprepInfo;

